import React, { useState, useEffect } from 'react';
import './App.css';

function Banner() {
    return (
        <div className="banner">
                <img src="/assets/logo.png" alt="Logo" className="banner-logo" />
        </div>
    );
}

function App() {
    const [tokenId, setTokenId] = useState('');  // Add this line
    const [tokenIds, setTokenIds] = useState([]);
    const [selectedAsset, setSelectedAsset] = useState('');
    const [imageUrl, setImageUrl] = useState('/assets/face.png');  // Update this line

    const [fade, setFade] = useState(false);

    // Function to update the image with fade effect
    const updateImageWithFade = (newImageUrl) => {
        setFade(true);  // Start with fade out
        setTimeout(() => {
            setImageUrl(newImageUrl);  // Change the image
            setFade(false);  // Fade in the new image
        }, 10000);  // 500ms for fade-out effect
    };

    useEffect(() => {
        fetch('/token-ids')
            .then(response => response.json())
            .then(data => {
                const sortedData = data.sort((a, b) => parseInt(a) - parseInt(b));
                setTokenIds(sortedData);
            })
            .catch(error => console.error('Error:', error));
    }, []);

    const fetchAsset = (newTokenId, newSelectedAsset) => {
        if (newTokenId && newSelectedAsset) {
            fetch(`/get-asset?tokenId=${newTokenId}&assetType=${newSelectedAsset}`)
                .then(response => {
                    if (!response.ok) {
                        throw new Error('Network response was not ok');
                    }
                    return response.json();
                })
                .then(data => {
                    setImageUrl(data.image_url);
                })
                .catch(error => {
                    console.error('Error:', error);
                    setImageUrl(''); // Clear the image if there's an error
                });
        }
    };

    const handleTokenChange = (event) => {
        setTokenId(event.target.value);
        fetchAsset(event.target.value, selectedAsset);
    };

    const handleAssetChange = (event) => {
        setSelectedAsset(event.target.value);
        fetchAsset(tokenId, event.target.value);
    };

    return (
        <div className="App">
            <Banner />
            <header className="App-header">
                <select value={tokenId} onChange={handleTokenChange}>
                    <option value="">Select Token ID</option>
                    {tokenIds.map(id => (
                        <option key={id} value={id}>{id}</option>
                    ))}
                </select>
                <select value={selectedAsset} onChange={handleAssetChange}>
                    <option value="">Select an Asset</option>
                    <option value="gm">gm</option>
                    <option value="cheers">cheers</option>
                    <option value="peace">peace</option>
                </select>
                <div id="asset-display" className={fade ? 'fade-effect fade-effect-fade' : 'fade-effect'}>
                    {imageUrl && <img src={imageUrl} alt="Processed NFT" />}
                </div>
            </header>
        </div>
    );
}

export default App;
